#!/usr/bin/env python3\n\"\"\"\nTest Refugee Decision Tracker Integration with Existing Flee System\n\nDemonstrates how the refugee tracker integrates with existing:\n- calculateMoveChance() function\n- Person.calculate_cognitive_pressure() method\n- Person.log_decision() method\n- System 2 activation logic\n\"\"\"\n\nimport sys\nfrom pathlib import Path\n\n# Add current directory to path\ncurrent_dir = Path(__file__).parent\nif str(current_dir) not in sys.path:\n    sys.path.insert(0, str(current_dir))\n\ndef test_refugee_tracker_integration():\n    \"\"\"Test integration with existing Flee S1/S2 system\"\"\"\n    print(\"🧠 TESTING REFUGEE TRACKER INTEGRATION WITH EXISTING FLEE S1/S2\")\n    print(\"=\" * 70)\n    \n    try:\n        # Import existing Flee modules\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Ecosystem, Person, Location\n        from flee import moving\n        from scripts.refugee_decision_tracker import RefugeeDecisionTracker, track_refugee_decision\n        \n        print(\"✅ Successfully imported existing Flee modules\")\n        \n        # Initialize existing Flee settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n        SimulationSettings.move_rules[\"conflict_threshold\"] = 0.5\n        print(\"✅ Initialized existing Flee settings with S1/S2 enabled\")\n        \n        # Create ecosystem using existing Flee classes\n        ecosystem = Ecosystem()\n        \n        # Create locations using existing Location class\n        origin = ecosystem.addLocation(\"Origin\", x=0, y=0, movechance=1.0, capacity=-1, pop=1000)\n        town = ecosystem.addLocation(\"Town\", x=100, y=0, movechance=0.3, capacity=-1, pop=500)\n        camp = ecosystem.addLocation(\"Camp\", x=200, y=0, movechance=0.001, capacity=2000, pop=0)\n        \n        # Link locations using existing methods\n        ecosystem.linkUp(\"Origin\", \"Town\", 100.0)\n        ecosystem.linkUp(\"Town\", \"Camp\", 100.0)\n        \n        print(\"✅ Created test ecosystem using existing Flee infrastructure\")\n        \n        # Initialize refugee tracker\n        tracker = RefugeeDecisionTracker()\n        \n        # Create test agents with varying connectivity (existing Person class)\n        test_agents = []\n        for i in range(10):\n            connections = i  # 0 to 9 connections\n            agent = Person(origin, attributes={\"connections\": connections})\n            test_agents.append(agent)\n            ecosystem.addAgent(agent.location, attributes={\"connections\": connections})\n        \n        print(f\"✅ Created {len(test_agents)} agents using existing Person class\")\n        \n        # Test integration with existing calculateMoveChance\n        print(\"\\n📊 TESTING INTEGRATION WITH EXISTING calculateMoveChance()\")\n        print(\"-\" * 60)\n        \n        for time in range(15):\n            # Escalate conflict using existing conflict attribute\n            conflict_level = min(time * 0.1, 1.0)\n            origin.conflict = conflict_level\n            origin.time_of_conflict = 0\n            \n            print(f\"\\nTime {time:2d}: Conflict level {conflict_level:.1f}\")\n            \n            # Test each agent with existing calculateMoveChance\n            for i, agent in enumerate(test_agents[:5]):  # Test first 5 agents\n                # Use existing calculateMoveChance function\n                movechance, system2_active = moving.calculateMoveChance(agent, False, time)\n                \n                # Use existing cognitive pressure calculation\n                cognitive_pressure = agent.calculate_cognitive_pressure(time)\n                \n                # Track decision using our refugee tracker\n                track_refugee_decision(agent, system2_active, movechance, time)\n                \n                # Show integration results\n                system = \"S2\" if system2_active else \"S1\"\n                print(f\"  Agent {i} (conn={agent.attributes['connections']:2d}): \"\n                      f\"{system} pressure={cognitive_pressure:.2f} move={movechance:.2f}\")\n                \n                # Test existing route selection if moving\n                if movechance > 0.5:\n                    route = moving.selectRoute(agent, time, system2_active=system2_active)\n                    if route:\n                        print(f\"    → Route selected: {' → '.join(route)}\")\n                        # Track route in refugee tracker\n                        track_refugee_decision(agent, system2_active, movechance, time, route)\n        \n        print(\"\\n📈 ANALYZING RESULTS USING REFUGEE TRACKER\")\n        print(\"-\" * 50)\n        \n        # Generate analysis using refugee tracker\n        analysis = tracker.generate_refugee_analysis_report()\n        \n        # Display evacuation timing analysis\n        if 'evacuation_timing' in analysis and 'error' not in analysis['evacuation_timing']:\n            timing = analysis['evacuation_timing']\n            print(f\"\\n🏃 EVACUATION TIMING ANALYSIS:\")\n            print(f\"  S1 mean timing: {timing['s1_mean_timing']:.1f} days\")\n            print(f\"  S2 mean timing: {timing['s2_mean_timing']:.1f} days\")\n            print(f\"  Difference: {timing['timing_difference']:.1f} days\")\n            print(f\"  Effect size: {timing['effect_size']:.2f}\")\n        \n        # Display cognitive activation analysis\n        if 'cognitive_activation' in analysis:\n            activation = analysis['cognitive_activation']\n            print(f\"\\n🧠 COGNITIVE ACTIVATION ANALYSIS:\")\n            print(f\"  Total decisions: {activation['total_decisions']}\")\n            print(f\"  S2 activation rate: {activation['s2_activation_rate']:.1%}\")\n            \n            if 'pressure_threshold_analysis' in activation and 'error' not in activation['pressure_threshold_analysis']:\n                threshold = activation['pressure_threshold_analysis']\n                print(f\"  S1 max pressure: {threshold['s1_max_pressure']:.2f}\")\n                print(f\"  S2 min pressure: {threshold['s2_min_pressure']:.2f}\")\n        \n        # Display route planning analysis\n        if 'route_planning' in analysis and 'error' not in analysis['route_planning']:\n            routing = analysis['route_planning']\n            print(f\"\\n🗺️  ROUTE PLANNING ANALYSIS:\")\n            print(f\"  S1 mean route length: {routing['s1_mean_route_length']:.1f}\")\n            print(f\"  S2 mean route length: {routing['s2_mean_route_length']:.1f}\")\n            print(f\"  Difference: {routing['route_length_difference']:.1f}\")\n            print(f\"  Effect size: {routing['effect_size']:.2f}\")\n        \n        # Save results\n        tracker.save_decision_data(\"refugee_test_output\")\n        print(f\"\\n💾 Saved analysis results to refugee_test_output/\")\n        \n        print(\"\\n✅ INTEGRATION TEST SUCCESSFUL!\")\n        print(\"\\n🎯 KEY FINDINGS:\")\n        print(\"  • Refugee tracker successfully integrates with existing calculateMoveChance()\")\n        print(\"  • Uses existing Person.calculate_cognitive_pressure() method\")\n        print(\"  • Leverages existing System 2 activation logic\")\n        print(\"  • Maintains backward compatibility with existing Flee system\")\n        print(\"  • Provides refugee-specific analysis on top of existing infrastructure\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ Integration test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\ndef test_existing_flee_compatibility():\n    \"\"\"Test that existing Flee functionality still works\"\"\"\n    print(\"\\n🔄 TESTING BACKWARD COMPATIBILITY WITH EXISTING FLEE\")\n    print(\"=\" * 60)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Ecosystem\n        from flee import moving\n        \n        # Test existing Flee without refugee enhancements\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = False  # Disable S1/S2\n        \n        ecosystem = Ecosystem()\n        origin = ecosystem.addLocation(\"TestOrigin\", x=0, y=0, movechance=0.5)\n        dest = ecosystem.addLocation(\"TestDest\", x=100, y=0, movechance=0.1)\n        ecosystem.linkUp(\"TestOrigin\", \"TestDest\", 100.0)\n        \n        # Create agent using existing Person class\n        agent = ecosystem.addAgent(location=origin)\n        \n        # Test existing calculateMoveChance without S1/S2\n        movechance, system2_active = moving.calculateMoveChance(agent, False, 1)\n        \n        print(f\"✅ Existing calculateMoveChance works: movechance={movechance:.2f}\")\n        print(f\"✅ System 2 correctly disabled: system2_active={system2_active}\")\n        \n        # Test existing route selection\n        route = moving.selectRoute(agent, 1)\n        print(f\"✅ Existing selectRoute works: route={route}\")\n        \n        print(\"\\n✅ BACKWARD COMPATIBILITY CONFIRMED\")\n        print(\"  • Existing Flee functionality unchanged\")\n        print(\"  • Refugee enhancements are additive only\")\n        print(\"  • No breaking changes to existing API\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ Compatibility test failed: {e}\")\n        return False\n\nif __name__ == \"__main__\":\n    print(\"🚀 STARTING REFUGEE TRACKER INTEGRATION TESTS\")\n    print(\"=\" * 70)\n    \n    # Test integration with existing system\n    integration_success = test_refugee_tracker_integration()\n    \n    # Test backward compatibility\n    compatibility_success = test_existing_flee_compatibility()\n    \n    print(\"\\n\" + \"=\" * 70)\n    if integration_success and compatibility_success:\n        print(\"🎉 ALL TESTS PASSED - REFUGEE TRACKER SUCCESSFULLY INTEGRATED!\")\n        print(\"\\n📋 NEXT STEPS:\")\n        print(\"  1. Run evacuation timing scenarios\")\n        print(\"  2. Test bottleneck challenge scenarios\")\n        print(\"  3. Validate S1 vs S2 differences in refugee contexts\")\n    else:\n        print(\"❌ SOME TESTS FAILED - CHECK INTEGRATION\")\n        sys.exit(1)\n"